  1→// serval-router/types.zig
  2→//! Router Types
  3→//!
  4→//! Route matching and configuration types for content-based routing.
  5→//! Routes requests to backend pools based on host and path matching.
  6→//!
  7→//! TigerStyle: Fixed-size types, no allocation, explicit defaults.
  8→
  9→const std = @import("std");
 10→const assert = std.debug.assert;
 11→const core = @import("serval-core");
 12→const lb = @import("serval-lb");
 13→
 14→pub const LbHandler = lb.LbHandler;
 15→pub const LbConfig = lb.LbConfig;
 16→pub const Upstream = core.Upstream;
 17→
 18→// =============================================================================
 19→// Path Matching
 20→// =============================================================================
 21→
 22→/// Path match mode for route matching.
 23→///
 24→/// TigerStyle: Tagged union prevents invalid states (can't be both exact and prefix).
 25→pub const PathMatch = union(enum) {
 26→    /// Exact path match: "/api/v1/users" matches only "/api/v1/users".
 27→    /// Does not match "/api/v1/users/" or "/api/v1/users/123".
 28→    /// Does not match "/api/v1/users?foo=bar" (use exactPath for that).
 29→    exact: []const u8,
 30→
 31→    /// Exact path match ignoring query string: "/healthz" matches both
 32→    /// "/healthz" and "/healthz?verbose=true".
 33→    /// Does not match "/healthz/" or "/healthzfoo".
 34→    exactPath: []const u8,
 35→
 36→    /// Prefix match: "/api/" matches "/api/users", "/api/v1/health", etc.
 37→    /// The prefix must match the start of the request path.
 38→    prefix: []const u8,
 39→
 40→    /// Check if a request path matches this pattern.
 41→    /// TigerStyle: Bounded, returns bool (no allocation).
 42→    pub fn matches(self: PathMatch, request_path: []const u8) bool {
 43→        return switch (self) {
 44→            .exact => |pattern| std.mem.eql(u8, request_path, pattern),
 45→            .exactPath => |pattern| matchExactPath(pattern, request_path),
 46→            .prefix => |pattern| std.mem.startsWith(u8, request_path, pattern),
 47→        };
 48→    }
 49→
 50→    /// Match path exactly, ignoring query string.
 51→    /// TigerStyle: Pure function, bounded comparison.
 52→    fn matchExactPath(pattern: []const u8, request_path: []const u8) bool {
 53→        // S1: Preconditions - pattern from route config, path from request
 54→        assert(pattern.len > 0); // Route config validation ensures non-empty
 55→        assert(request_path.len > 0); // HTTP request path always starts with /
 56→
 57→        // Exact match (no query string)
 58→        if (std.mem.eql(u8, request_path, pattern)) return true;
 59→
 60→        // Match with query string: pattern + "?" + query
 61→        if (request_path.len > pattern.len) {
 62→            if (std.mem.startsWith(u8, request_path, pattern)) {
 63→                return request_path[pattern.len] == '?';
 64→            }
 65→        }
 66→        return false;
 67→    }
 68→
 69→    /// Get the pattern string for logging/debugging.
 70→    /// TigerStyle: Trivial accessor, assertion-exempt.
 71→    pub fn getPattern(self: PathMatch) []const u8 {
 72→        return switch (self) {
 73→            inline else => |p| p,
 74→        };
 75→    }
 76→};
 77→
 78→// =============================================================================
 79→// Route Matcher
 80→// =============================================================================
 81→
 82→/// Route match criteria combining host and path matching.
 83→///
 84→/// Both host and path must match for the route to be selected.
 85→/// TigerStyle: Optional host (null = any host), required path.
 86→pub const RouteMatcher = struct {
 87→    /// Host to match (null = match any host).
 88→    /// Compared case-insensitively per RFC 9110.
 89→    host: ?[]const u8 = null,
 90→
 91→    /// Path match mode (exact or prefix).
 92→    path: PathMatch,
 93→
 94→    /// Check if a request matches this route.
 95→    /// TigerStyle: Returns bool, no allocation.
 96→    pub fn matches(self: RouteMatcher, request_host: ?[]const u8, request_path: []const u8) bool {
 97→        // Check host match (if specified)
 98→        if (self.host) |expected_host| {
 99→            const actual_host = request_host orelse return false;
100→            // Strip port if present. RFC 9110 §7.2: Host header may include port.
101→            const hostname = if (std.mem.indexOfScalar(u8, actual_host, ':')) |i| actual_host[0..i] else actual_host;
102→
103→            if (!matchHost(expected_host, hostname)) {
104→                return false;
105→            }
106→        }
107→
108→        // Check path match
109→        return self.path.matches(request_path);
110→    }
111→
112→    /// Match hostname against pattern, supporting wildcards.
113→    ///
114→    /// Wildcard patterns (e.g., "*.example.com") match exactly one subdomain level:
115→    /// - "*.example.com" matches "foo.example.com", "bar.example.com"
116→    /// - Does NOT match "example.com" (requires a subdomain)
117→    /// - Does NOT match "foo.bar.example.com" (only one subdomain level)
118→    ///
119→    /// TigerStyle: Pure function, no allocation, bounded iteration.
120→    fn matchHost(pattern: []const u8, hostname: []const u8) bool {
121→        // Preconditions: pattern comes from route config, hostname from request
122→        assert(pattern.len > 0); // Route config validation ensures non-empty
123→        assert(hostname.len > 0); // Caller strips port, empty hostname rejected earlier
124→
125→        // Check for wildcard pattern: must start with "*."
126→        if (std.mem.startsWith(u8, pattern, "*.")) {
127→            const base_domain = pattern[2..]; // Skip "*."
128→
129→            // Base domain must be non-empty (e.g., "*.com" has base "com")
130→            if (base_domain.len == 0) {
131→                return false;
132→            }
133→
134→            // Hostname must be longer than base domain + 1 (for subdomain + dot)
135→            // This ensures there's room for at least "x." before the base domain
136→            if (hostname.len <= base_domain.len + 1) {
137→                return false;
138→            }
139→
140→            // Hostname must end with "." + base_domain (case-insensitive)
141→            // We check if hostname ends with the base domain pattern
142→            const suffix_start = hostname.len - base_domain.len;
143→            const suffix = hostname[suffix_start..];
144→            if (!std.ascii.eqlIgnoreCase(suffix, base_domain)) {
145→                return false;
146→            }
147→
148→            // Character before suffix must be a dot
149→            if (hostname[suffix_start - 1] != '.') {
150→                return false;
151→            }
152→
153→            // Extract the subdomain part (everything before the dot + base_domain)
154→            const subdomain = hostname[0 .. suffix_start - 1];
155→
156→            // Subdomain must not be empty and must not contain dots
157→            // (ensures exactly one subdomain level: "foo" OK, "foo.bar" NOT OK)
158→            if (subdomain.len == 0) {
159→                return false;
160→            }
161→
162→            // Check for dots in subdomain - if found, reject (multi-level subdomain)
163→            // TigerStyle: indexOfScalar is bounded by subdomain.len
164→            if (std.mem.indexOfScalar(u8, subdomain, '.') != null) {
165→                return false;
166→            }
167→
168→            return true;
169→        }
170→
171→        // Non-wildcard: exact case-insensitive match (RFC 9110 §4.2.3)
172→        return std.ascii.eqlIgnoreCase(pattern, hostname);
173→    }
174→};
175→
176→// =============================================================================
177→// Route
178→// =============================================================================
179→
180→/// A single route entry mapping match criteria to a backend pool.
181→///
182→/// Routes are evaluated in order; first match wins.
183→/// TigerStyle: Fixed-size, explicit pool_idx for array indexing.
184→pub const Route = struct {
185→    /// Route name for logging/debugging (e.g., "api-v1", "static-assets").
186→    name: []const u8,
187→
188→    /// Match criteria (host + path).
189→    matcher: RouteMatcher,
190→
191→    /// Index into the backend pools array.
192→    /// TigerStyle: u8 allows up to 256 pools (more than sufficient).
193→    pool_idx: u8,
194→
195→    /// Strip matched prefix before forwarding.
196→    /// Only applies to prefix matches.
197→    /// Example: route "/api/" -> backend, strip=true: "/api/users" -> "/users"
198→    strip_prefix: bool = false,
199→};
200→
201→// =============================================================================
202→// Pool Configuration
203→// =============================================================================
204→
205→/// Configuration for a backend pool with load balancer settings.
206→///
207→/// Each pool has its own set of upstreams and LB configuration.
208→/// TigerStyle: Fixed-size references, no heap allocation.
209→pub const PoolConfig = struct {
210→    /// Pool name for logging/debugging (e.g., "api-backends", "static-servers").
211→    name: []const u8,
212→
213→    /// Upstream servers in this pool.
214→    /// Slice into caller-owned array (not heap-allocated).
215→    upstreams: []const Upstream,
216→
217→    /// Load balancer configuration for this pool.
218→    lb_config: LbConfig = .{},
219→};
220→
221→// =============================================================================
222→// Tests
223→// =============================================================================
224→
225→test "PathMatch exact matches" {
226→    const pattern = PathMatch{ .exact = "/api/v1/users" };
227→
228→    // Exact match succeeds
229→    try std.testing.expect(pattern.matches("/api/v1/users"));
230→
231→    // Trailing slash fails
232→    try std.testing.expect(!pattern.matches("/api/v1/users/"));
233→
234→    // Subpath fails
235→    try std.testing.expect(!pattern.matches("/api/v1/users/123"));
236→
237→    // Different path fails
238→    try std.testing.expect(!pattern.matches("/api/v2/users"));
239→
240→    // Prefix of pattern fails
241→    try std.testing.expect(!pattern.matches("/api/v1"));
242→}
243→
244→test "PathMatch prefix matches" {
245→    const pattern = PathMatch{ .prefix = "/api/" };
246→
247→    // Prefix matches
248→    try std.testing.expect(pattern.matches("/api/"));
249→    try std.testing.expect(pattern.matches("/api/users"));
250→    try std.testing.expect(pattern.matches("/api/v1/health"));
251→
252→    // Non-prefix fails
253→    try std.testing.expect(!pattern.matches("/v1/api/"));
254→    try std.testing.expect(!pattern.matches("/apifoo"));
255→    try std.testing.expect(!pattern.matches("/ap"));
256→}
257→
258→test "PathMatch exactPath matches" {
259→    const pattern = PathMatch{ .exactPath = "/healthz" };
260→
261→    // Exact match succeeds
262→    try std.testing.expect(pattern.matches("/healthz"));
263→
264→    // With query string succeeds
265→    try std.testing.expect(pattern.matches("/healthz?"));
266→    try std.testing.expect(pattern.matches("/healthz?verbose=true"));
267→    try std.testing.expect(pattern.matches("/healthz?foo=bar&baz=qux"));
268→
269→    // Trailing slash fails
270→    try std.testing.expect(!pattern.matches("/healthz/"));
271→
272→    // Subpath fails
273→    try std.testing.expect(!pattern.matches("/healthz/deep"));
274→
275→    // Similar prefix fails (no query string separator)
276→    try std.testing.expect(!pattern.matches("/healthzfoo"));
277→    try std.testing.expect(!pattern.matches("/healthz-extended"));
278→
279→    // Different path fails
280→    try std.testing.expect(!pattern.matches("/readyz"));
281→
282→    // Prefix of pattern fails
283→    try std.testing.expect(!pattern.matches("/health"));
284→}
285→
286→test "PathMatch exactPath edge cases" {
287→    // Root path
288→    const root = PathMatch{ .exactPath = "/" };
289→    try std.testing.expect(root.matches("/"));
290→    try std.testing.expect(root.matches("/?foo=bar"));
291→    try std.testing.expect(!root.matches("/api"));
292→
293→    // Path with existing query-like chars
294→    const config = PathMatch{ .exactPath = "/config" };
295→    try std.testing.expect(config.matches("/config"));
296→    try std.testing.expect(config.matches("/config?format=json"));
297→    try std.testing.expect(!config.matches("/config/"));
298→    try std.testing.expect(!config.matches("/configuration"));
299→}
300→
301→test "PathMatch getPattern" {
302→    const exact = PathMatch{ .exact = "/health" };
303→    const exact_path = PathMatch{ .exactPath = "/healthz" };
304→    const prefix = PathMatch{ .prefix = "/api/" };
305→
306→    try std.testing.expectEqualStrings("/health", exact.getPattern());
307→    try std.testing.expectEqualStrings("/healthz", exact_path.getPattern());
308→    try std.testing.expectEqualStrings("/api/", prefix.getPattern());
309→}
310→
311→test "RouteMatcher host and path" {
312→    const matcher = RouteMatcher{
313→        .host = "api.example.com",
314→        .path = .{ .prefix = "/v1/" },
315→    };
316→
317→    // Both match
318→    try std.testing.expect(matcher.matches("api.example.com", "/v1/users"));
319→
320→    // Host mismatch
321→    try std.testing.expect(!matcher.matches("www.example.com", "/v1/users"));
322→
323→    // Path mismatch
324→    try std.testing.expect(!matcher.matches("api.example.com", "/v2/users"));
325→
326→    // Null host with required host
327→    try std.testing.expect(!matcher.matches(null, "/v1/users"));
328→}
329→
330→test "RouteMatcher any host" {
331→    const matcher = RouteMatcher{
332→        .host = null, // Any host
333→        .path = .{ .exact = "/health" },
334→    };
335→
336→    // Any host matches
337→    try std.testing.expect(matcher.matches("api.example.com", "/health"));
338→    try std.testing.expect(matcher.matches("www.example.com", "/health"));
339→    try std.testing.expect(matcher.matches(null, "/health"));
340→
341→    // Path must still match
342→    try std.testing.expect(!matcher.matches("api.example.com", "/ready"));
343→}
344→
345→test "RouteMatcher case insensitive host" {
346→    const matcher = RouteMatcher{
347→        .host = "API.Example.COM",
348→        .path = .{ .prefix = "/" },
349→    };
350→
351→    // Case variations match
352→    try std.testing.expect(matcher.matches("api.example.com", "/"));
353→    try std.testing.expect(matcher.matches("API.EXAMPLE.COM", "/"));
354→    try std.testing.expect(matcher.matches("Api.Example.Com", "/"));
355→}
356→
357→test "RouteMatcher strips port from host" {
358→    const matcher = RouteMatcher{
359→        .host = "api.example.com",
360→        .path = .{ .prefix = "/" },
361→    };
362→
363→    // Host with port should match after stripping (RFC 9110 §7.2)
364→    try std.testing.expect(matcher.matches("api.example.com:8080", "/"));
365→    try std.testing.expect(matcher.matches("api.example.com:443", "/"));
366→    try std.testing.expect(matcher.matches("api.example.com:31588", "/")); // NodePort
367→
368→    // Without port still works
369→    try std.testing.expect(matcher.matches("api.example.com", "/"));
370→
371→    // Different host with port should not match
372→    try std.testing.expect(!matcher.matches("other.example.com:8080", "/"));
373→}
374→
375→test "Route defaults" {
376→    const route = Route{
377→        .name = "default",
378→        .matcher = .{ .path = .{ .prefix = "/" } },
379→        .pool_idx = 0,
380→    };
381→
382→    // strip_prefix defaults to false
383→    try std.testing.expect(!route.strip_prefix);
384→}
385→
386→test "Route with strip_prefix" {
387→    const route = Route{
388→        .name = "api",
389→        .matcher = .{ .path = .{ .prefix = "/api/" } },
390→        .pool_idx = 1,
391→        .strip_prefix = true,
392→    };
393→
394→    try std.testing.expectEqualStrings("api", route.name);
395→    try std.testing.expectEqual(@as(u8, 1), route.pool_idx);
396→    try std.testing.expect(route.strip_prefix);
397→}
398→
399→test "PoolConfig defaults" {
400→    const upstreams = [_]Upstream{
401→        .{ .host = "127.0.0.1", .port = 8001, .idx = 0 },
402→    };
403→
404→    const pool = PoolConfig{
405→        .name = "test-pool",
406→        .upstreams = &upstreams,
407→    };
408→
409→    try std.testing.expectEqualStrings("test-pool", pool.name);
410→    try std.testing.expectEqual(@as(usize, 1), pool.upstreams.len);
411→    // LbConfig has defaults
412→    try std.testing.expect(pool.lb_config.enable_probing);
413→}
414→
415→test "PoolConfig with custom lb_config" {
416→    const upstreams = [_]Upstream{
417→        .{ .host = "127.0.0.1", .port = 8001, .idx = 0 },
418→        .{ .host = "127.0.0.1", .port = 8002, .idx = 1 },
419→    };
420→
421→    const pool = PoolConfig{
422→        .name = "custom-pool",
423→        .upstreams = &upstreams,
424→        .lb_config = .{
425→            .unhealthy_threshold = 5,
426→            .healthy_threshold = 3,
427→            .enable_probing = false,
428→        },
429→    };
430→
431→    try std.testing.expectEqual(@as(u8, 5), pool.lb_config.unhealthy_threshold);
432→    try std.testing.expectEqual(@as(u8, 3), pool.lb_config.healthy_threshold);
433→    try std.testing.expect(!pool.lb_config.enable_probing);
434→}
435→
436→test "RouteMatcher wildcard host" {
437→    const matcher = RouteMatcher{
438→        .host = "*.example.com",
439→        .path = .{ .prefix = "/" },
440→    };
441→
442→    // Should match single subdomain
443→    try std.testing.expect(matcher.matches("foo.example.com", "/"));
444→    try std.testing.expect(matcher.matches("bar.example.com", "/"));
445→    try std.testing.expect(matcher.matches("FOO.EXAMPLE.COM", "/")); // case-insensitive
446→    try std.testing.expect(matcher.matches("foo.example.com:8080", "/")); // with port
447→
448→    // Should NOT match base domain
449→    try std.testing.expect(!matcher.matches("example.com", "/"));
450→
451→    // Should NOT match multiple subdomains
452→    try std.testing.expect(!matcher.matches("foo.bar.example.com", "/"));
453→
454→    // Should NOT match different domain
455→    try std.testing.expect(!matcher.matches("foo.other.com", "/"));
456→}
457→
458→test "RouteMatcher wildcard host edge cases" {
459→    // Wildcard with deeper base domain
460→    const matcher_deep = RouteMatcher{
461→        .host = "*.api.example.com",
462→        .path = .{ .prefix = "/" },
463→    };
464→
465→    try std.testing.expect(matcher_deep.matches("v1.api.example.com", "/"));
466→    try std.testing.expect(matcher_deep.matches("v2.api.example.com", "/"));
467→    try std.testing.expect(!matcher_deep.matches("api.example.com", "/")); // no subdomain
468→    try std.testing.expect(!matcher_deep.matches("foo.v1.api.example.com", "/")); // multi-level
469→
470→    // Single-label base domain (e.g., *.localhost - unusual but valid)
471→    const matcher_single = RouteMatcher{
472→        .host = "*.localhost",
473→        .path = .{ .prefix = "/" },
474→    };
475→
476→    try std.testing.expect(matcher_single.matches("app.localhost", "/"));
477→    try std.testing.expect(!matcher_single.matches("localhost", "/"));
478→    try std.testing.expect(!matcher_single.matches("foo.app.localhost", "/"));
479→}
480→
481→test "RouteMatcher wildcard host with path matching" {
482→    const matcher = RouteMatcher{
483→        .host = "*.example.com",
484→        .path = .{ .prefix = "/api/" },
485→    };
486→
487→    // Both host and path must match
488→    try std.testing.expect(matcher.matches("foo.example.com", "/api/users"));
489→    try std.testing.expect(!matcher.matches("foo.example.com", "/other")); // path mismatch
490→    try std.testing.expect(!matcher.matches("example.com", "/api/users")); // host mismatch
491→}
