100→    /// Errors:
101→    ///   error.TooManyPools: pool_configs.len > MAX_POOLS
102→    ///   error.TooManyRoutes: routes.len > MAX_ROUTES
103→    ///   error.TooManyAllowedHosts: allowed_hosts.len > MAX_ALLOWED_HOSTS
104→    ///   error.InvalidPoolIndex: Route references non-existent pool
105→    ///   error.EmptyPool: Pool has no upstreams
106→    ///   (+ any errors from LbHandler.init)
107→    pub fn init(
108→        self: *Self,
109→        routes: []const Route,
110→        pool_configs: []const PoolConfig,
111→        allowed_hosts: []const []const u8,
112→        client_ctx: ?*ssl.SSL_CTX,
113→        dns_resolver: ?*DnsResolver,
114→    ) !void {
115→        // Preconditions
116→        assert(pool_configs.len > 0); // S1: At least one pool required
117→        assert(routes.len <= MAX_ROUTES); // S1: Route count within bounds
118→        assert(allowed_hosts.len <= MAX_ALLOWED_HOSTS); // S1: allowed_hosts within bounds
119→
120→        // Validate pool count
121→        if (pool_configs.len > MAX_POOLS) {
122→            return error.TooManyPools;
123→        }
124→
125→        // Validate route count
126→        if (routes.len > MAX_ROUTES) {
127→            return error.TooManyRoutes;
128→        }
129→
130→        // Validate allowed_hosts count
131→        if (allowed_hosts.len > MAX_ALLOWED_HOSTS) {
132→            return error.TooManyAllowedHosts;
133→        }
134→
135→        // Validate all route pool indices before initialization
136→        for (routes) |route| {
137→            if (route.pool_idx >= pool_configs.len) {
138→                return error.InvalidPoolIndex;
139→            }
140→        }
141→
142→        // Validate pool configurations
143→        for (pool_configs) |cfg| {
144→            if (cfg.upstreams.len == 0) {
145→                return error.EmptyPool;
146→            }
147→        }
148→
149→        // Store route and allowed_hosts pointers (caller ensures data remains valid).
150→        self.routes = routes;
151→        self.allowed_hosts = allowed_hosts;
152→
153→        // Initialize pools with embedded LbHandlers.
154→        var initialized_count: usize = 0;
155→        errdefer {
156→            // Cleanup already-initialized pools on error
157→            for (self.pool_storage[0..initialized_count]) |*pool| {
158→                pool.lb_handler.deinit();
159→            }
160→        }
161→
162→        for (pool_configs, 0..) |cfg, i| {
163→            assert(i < MAX_POOLS); // S1: Loop invariant
164→            self.pool_storage[i].name = cfg.name;
165→            try self.pool_storage[i].lb_handler.init(
166→                cfg.upstreams,
167→                cfg.lb_config,
168→                client_ctx,
169→                dns_resolver,
170→            );
171→            initialized_count += 1;
172→        }
173→
174→        self.pools = self.pool_storage[0..pool_configs.len];
175→
176→        // Postconditions
177→        assert(self.routes.len == routes.len); // S2: All routes copied
178→        assert(self.pools.len == pool_configs.len); // S2: All pools initialized
179→        assert(self.pools.len > 0); // S2: At least one pool
180→        assert(self.allowed_hosts.len == allowed_hosts.len); // S2: allowed_hosts stored
181→    }
182→
183→    /// Clean up all pools and stop background probers.
184→    pub fn deinit(self: *Self) void {
185→        for (self.pools) |*pool| {
186→            pool.lb_handler.deinit();
187→        }
188→    }
189→
190→    /// Handler interface: select upstream for request.
191→    ///
192→    /// Validates host against allowed_hosts (if configured), matches request
193→    /// against routes (first match wins), then delegates to the matched pool's
194→    /// LbHandler for health-aware upstream selection.
195→    ///
196→    /// Returns Action.reject for:
197→    /// - 421 Misdirected Request: Host not in allowed_hosts
198→    /// - 404 Not Found: No matching route
199→    ///

